import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import SEO from '../components/SEO';

export default function NotFound() {
  const { pathname } = useLocation();
  return (
    <main className="section container text-center" style={{ padding: '5rem 1rem' }}>
      <SEO
        noIndex
        title="Page not found"
        description="The page you requested does not exist. Return to the Nova Shop home page or use the main navigation."
        canonicalUrl={pathname}
      />
      <h1 style={{ fontSize: '5rem', marginBottom: '0.5rem' }}>404</h1>
      <p style={{ marginBottom: '1.5rem', fontSize: '1.125rem' }}>This page does not exist.</p>
      <Link to="/" className="btn btn-primary">
        Back to home
      </Link>
    </main>
  );
}
